/* Specification helpers for FindLargestSplittableBlock.
 *
 * We pin npoints to 2, giving three candidate blocks (i = 0,1,2):
 *   B0: start = 0,      end = splitpoints[0]
 *   B1: start = sp[0],  end = splitpoints[1]
 *   B2: start = sp[1],  end = lz77size - 1
 * Pinning npoints lets the loop fully unwind and lets us write an exact-value
 * postcondition.  Three blocks (rather than two) are needed so that the middle
 * block B1 has start > 0: only then does the `longest = end - start` update
 * feed a later comparison, which is what makes the `end + start` mutant on that
 * assignment observable.
 *
 * The selection is a running maximum over the *valid* blocks (done[start]==0)
 * with a strict `>` test seeded at 0, so a block is chosen only if its size is
 * strictly greater than every earlier chosen size (earliest wins ties) and a
 * size-0 block is never chosen. */
#define FLSB_S0   (splitpoints[0])
#define FLSB_S1   (splitpoints[1])
#define FLSB_E2   ((lz77size) - 1)
#define FLSB_SZ0  (FLSB_S0)
#define FLSB_SZ1  (FLSB_S1 - FLSB_S0)
#define FLSB_SZ2  (FLSB_E2 - FLSB_S1)
#define FLSB_V0   (done[0] == 0)
#define FLSB_V1   (done[FLSB_S0] == 0)
#define FLSB_V2   (done[FLSB_S1] == 0)
/* B0 is chosen iff valid and size > 0 (initial longest is 0). */
#define FLSB_C0   (FLSB_V0 && FLSB_SZ0 > (size_t)0)
/* longest after iteration 0 */
#define FLSB_L0   (FLSB_C0 ? FLSB_SZ0 : (size_t)0)
/* B1 replaces the running best iff valid and strictly larger than longest. */
#define FLSB_SEL1 (FLSB_V1 && FLSB_SZ1 > FLSB_L0)
/* longest after iteration 1 */
#define FLSB_L1   (FLSB_SEL1 ? FLSB_SZ1 : FLSB_L0)
/* B2 replaces the running best iff valid and strictly larger than longest. */
#define FLSB_SEL2 (FLSB_V2 && FLSB_SZ2 > FLSB_L1)
/* Which block is the final selection (mutually exclusive). */
#define FLSB_FINAL2 (FLSB_SEL2)
#define FLSB_FINAL1 (FLSB_SEL1 && !FLSB_SEL2)
#define FLSB_FINAL0 (FLSB_C0 && !FLSB_SEL1 && !FLSB_SEL2)
/* A block was found iff any block was ever selected. */
#define FLSB_FOUND  (FLSB_C0 || FLSB_SEL1 || FLSB_SEL2)
static int FindLargestSplittableBlock(
    size_t lz77size, const unsigned char *done,
    const size_t *splitpoints, size_t npoints,
    size_t *lstart, size_t *lend)
__CPROVER_requires(npoints == 2)
__CPROVER_requires(lz77size >= 1 && lz77size <= 6)
__CPROVER_requires(__CPROVER_is_fresh(splitpoints, 2 * sizeof(*splitpoints)))
__CPROVER_requires(__CPROVER_is_fresh(done, lz77size * sizeof(*done)))
/* split points are sorted ascending and lie within the lz77 store */
__CPROVER_requires(FLSB_S0 <= FLSB_S1)
__CPROVER_requires(FLSB_S1 < lz77size)
__CPROVER_requires(__CPROVER_is_fresh(lstart, sizeof(*lstart)))
__CPROVER_requires(__CPROVER_is_fresh(lend, sizeof(*lend)))
__CPROVER_assigns(*lstart)
__CPROVER_assigns(*lend)
__CPROVER_ensures(__CPROVER_return_value == (FLSB_FOUND ? 1 : 0))
__CPROVER_ensures(FLSB_FINAL0 ==> (*lstart == 0 && *lend == FLSB_S0))
__CPROVER_ensures(FLSB_FINAL1 ==> (*lstart == FLSB_S0 && *lend == FLSB_S1))
__CPROVER_ensures(FLSB_FINAL2 ==> (*lstart == FLSB_S1 && *lend == FLSB_E2))
{
    size_t longest = 0;
    int found = 0;
    size_t i;
    for (i = 0; i <= npoints; i++)
    {
        size_t start = i == 0 ? 0 : splitpoints[i - 1];
        size_t end = i == npoints ? lz77size - 1 : splitpoints[i];
        if (!done[start] && end - start > longest)
        {
            *lstart = start;
            *lend = end;
            found = 1;
            longest = end - start;
        }
    }
    return found;
}
#undef FLSB_S0
#undef FLSB_S1
#undef FLSB_E2
#undef FLSB_SZ0
#undef FLSB_SZ1
#undef FLSB_SZ2
#undef FLSB_V0
#undef FLSB_V1
#undef FLSB_V2
#undef FLSB_C0
#undef FLSB_L0
#undef FLSB_SEL1
#undef FLSB_L1
#undef FLSB_SEL2
#undef FLSB_FINAL2
#undef FLSB_FINAL1
#undef FLSB_FINAL0
#undef FLSB_FOUND

/*
Prints the block split points as decimal and hex values in the terminal.
*/
static void PrintBlockSplitPoints(const ZopfliLZ77Store *lz77,
                                  const size_t *lz77splitpoints,
                                  size_t nlz77points)
{
    size_t *splitpoints = 0;
    size_t npoints = 0;
    size_t i;
    /* The input is given as lz77 indices, but we want to see the uncompressed
    index values. */
    size_t pos = 0;
    if (nlz77points > 0)
    {
        for (i = 0; i < lz77->size; i++)
        {
            size_t length = lz77->dists[i] == 0 ? 1 : lz77->litlens[i];
            if (lz77splitpoints[npoints] == i)
            {
                ZOPFLI_APPEND_DATA(pos, &splitpoints, &npoints);
                if (npoints == nlz77points)
                    break;
            }
            pos += length;
        }
    }
    assert(npoints == nlz77points);

